1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 1 / 10;
3	
4	const applyFirstInsuranceSurcharge = (premium: number): number =>
5	  premium + premium * FIRST_INSURANCE_SURCHARGE_RATE;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	const CURSED_SURCHARGE_RATE = 1 / 2;
17	
18	const COMPONENT_TYPES = ["rune", "moonstone"];
19	const BLOCK_SIZE = 3;
20	const BLOCK_PREMIUM = 60;
21	
22	type Item = { type: string; cursed?: boolean };
23	
24	const calculateItemPremium = (item: Item): number => {
25	  const basePremium = BASE_PREMIUMS[item.type] ?? 0;
26	  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
27	  return applyFirstInsuranceSurcharge(basePremium) + cursedSurcharge;
28	};
29	
30	export const quote = (items: Item[], customer: unknown, contractNumber: number): number => {
31	  const componentCounts: Record<string, number> = {};
32	  for (const item of items) {
33	    if (COMPONENT_TYPES.includes(item.type)) {
34	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
35	    }
36	  }
37	
38	  let totalPremium = 0;
39	
40	  for (const item of items) {
41	    if (COMPONENT_TYPES.includes(item.type) && componentCounts[item.type] === BLOCK_SIZE) {
42	      continue;
43	    }
44	    totalPremium += calculateItemPremium(item);
45	  }
46	
47	  for (const type of COMPONENT_TYPES) {
48	    if (componentCounts[type] === BLOCK_SIZE) {
49	      totalPremium += applyFirstInsuranceSurcharge(BLOCK_PREMIUM);
50	    }
51	  }
52	
53	  return Math.ceil(totalPremium) + PROCESSING_FEE;
54	};
